import { createContext, useContext, useState, useEffect } from 'react';

const CartContext = createContext();

export const useCart = () => useContext(CartContext);

export const CartProvider = ({ children }) => {
  const [cartItems, setCartItems] = useState([]);

  useEffect(() => {
    const storedCart = localStorage.getItem('ec_cart');
    if (storedCart) {
      setCartItems(JSON.parse(storedCart));
    }
  }, []);

  const saveCart = (items) => {
    setCartItems(items);
    localStorage.setItem('ec_cart', JSON.stringify(items));
  };

  const addToCart = (product, quantity = 1) => {
    const existingItem = cartItems.find(item => item.productId === product.id);
    let newCart;
    if (existingItem) {
      newCart = cartItems.map(item => 
        item.productId === product.id 
          ? { ...item, quantity: item.quantity + quantity }
          : item
      );
    } else {
      newCart = [...cartItems, { 
        productId: product.id, 
        name: product.name, 
        price: product.price, 
        image: product.image,
        quantity 
      }];
    }
    saveCart(newCart);
  };

  const removeFromCart = (productId) => {
    const newCart = cartItems.filter(item => item.productId !== productId);
    saveCart(newCart);
  };

  const updateQuantity = (productId, newQuantity) => {
    if (newQuantity <= 0) {
      removeFromCart(productId);
      return;
    }
    const newCart = cartItems.map(item =>
      item.productId === productId ? { ...item, quantity: newQuantity } : item
    );
    saveCart(newCart);
  };
  
  const clearCart = () => {
    saveCart([]);
  }

  const getCartTotal = () => {
    return cartItems.reduce((total, item) => total + item.price * item.quantity, 0);
  };

  return (
    <CartContext.Provider value={{ cartItems, addToCart, removeFromCart, updateQuantity, clearCart, getCartTotal }}>
      {children}
    </CartContext.Provider>
  );
};

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useCart } from '../contexts/CartContext';
import { createOrderAPI } from '../data/api';
import styles from './Checkout.module.css';

const Checkout = () => {
  const { user } = useAuth();
  const { cartItems, getCartTotal, clearCart } = useCart();
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    name: user?.name || '',
    phone: user?.phone || '',
    address: user?.address || '',
    note: ''
  });
  const [paymentMethod, setPaymentMethod] = useState('cod');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const shippingFee = 30000; // Fake fixed shipping fee for Viettel Post
  const totalPayment = getCartTotal() + shippingFee;

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleCheckout = async (e) => {
    e.preventDefault();
    if (!formData.name || !formData.phone || !formData.address) {
      setError('Vui lòng điền đầy đủ thông tin giao hàng');
      return;
    }

    try {
      setLoading(true);
      setError('');
      
      const orderData = {
        userId: user.id,
        items: cartItems,
        totalAmount: getCartTotal(),
        shippingFee,
        totalPayment,
        paymentMethod,
        paymentStatus: paymentMethod === 'vnpay' ? 'paid_mock' : 'unpaid',
        shippingMethod: 'viettel_post',
        customerInfo: formData
      };

      // Giả lập redirect qua VNPay nếu chọn VNPay
      if (paymentMethod === 'vnpay') {
         await new Promise(r => setTimeout(r, 1500));
         alert('Đang chuyển hướng sang cổng thanh toán VNPay (Giả lập)... Giao dịch thành công!');
      }

      await createOrderAPI(orderData);
      clearCart();
      alert('Đặt hàng thành công! Mã đơn hàng của bạn đã được ghi nhận.');
      navigate('/');
      
    } catch (err) {
      setError('Có lỗi xảy ra khi đặt hàng. Vui lòng thử lại.');
    } finally {
      setLoading(false);
    }
  };

  if (cartItems.length === 0) {
    navigate('/cart');
    return null;
  }

  return (
    <div className={`container ${styles.checkoutPage}`}>
      <h1 className={styles.pageTitle}>Thanh toán</h1>
      
      <form onSubmit={handleCheckout} className={styles.layout}>
        <div className={styles.leftCol}>
          <div className={styles.card}>
            <h2 className={styles.cardTitle}>Thông tin giao hàng</h2>
            {error && <div className={styles.errorAlert}>{error}</div>}
            
            <div className={styles.formGroup}>
              <label>Họ và tên người nhận</label>
              <input type="text" name="name" className="input-field" value={formData.name} onChange={handleChange} required />
            </div>
            <div className={styles.formGroup}>
              <label>Số điện thoại</label>
              <input type="tel" name="phone" className="input-field" value={formData.phone} onChange={handleChange} required />
            </div>
            <div className={styles.formGroup}>
              <label>Địa chỉ nhận hàng chi tiết</label>
              <textarea name="address" className="input-field" rows="3" value={formData.address} onChange={handleChange} required></textarea>
            </div>
            <div className={styles.formGroup}>
              <label>Ghi chú đơn hàng (Tùy chọn)</label>
              <textarea name="note" className="input-field" rows="2" value={formData.note} onChange={handleChange}></textarea>
            </div>
          </div>

          <div className={styles.card}>
            <h2 className={styles.cardTitle}>Phương thức thanh toán</h2>
            <div className={styles.paymentMethods}>
              <label className={`${styles.paymentOption} ${paymentMethod === 'cod' ? styles.active : ''}`}>
                <input type="radio" name="payment" value="cod" checked={paymentMethod === 'cod'} onChange={() => setPaymentMethod('cod')} />
                <div className={styles.payContent}>
                  <strong>Thanh toán khi nhận hàng (COD)</strong>
                  <p>Phí thu hộ tùy thuộc vào bên vận chuyển (Viettel Post).</p>
                </div>
              </label>
              
              <label className={`${styles.paymentOption} ${paymentMethod === 'vnpay' ? styles.active : ''}`}>
                <input type="radio" name="payment" value="vnpay" checked={paymentMethod === 'vnpay'} onChange={() => setPaymentMethod('vnpay')} />
                <div className={styles.payContent}>
                  <strong>Thanh toán qua VNPay</strong>
                  <p>Quét mã QR hoặc dùng thẻ ATM/Visa/MasterCard.</p>
                </div>
              </label>
            </div>
          </div>
        </div>

        <div className={styles.rightCol}>
          <div className={styles.card}>
            <h2 className={styles.cardTitle}>Đơn hàng của bạn ({cartItems.length} sản phẩm)</h2>
            <div className={styles.orderItems}>
              {cartItems.map(item => (
                <div key={item.productId} className={styles.orderItem}>
                   <img src={item.image} alt={item.name} className={styles.itemImage} />
                   <div className={styles.itemDetails}>
                     <h4>{item.name}</h4>
                     <p>SL: {item.quantity}</p>
                   </div>
                   <div className={styles.itemPrice}>
                     {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(item.price * item.quantity)}
                   </div>
                </div>
              ))}
            </div>
            
            <div className={styles.summaryTotals}>
               <div className={styles.summaryRow}>
                 <span>Tạm tính</span>
                 <span>{new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(getCartTotal())}</span>
               </div>
               <div className={styles.summaryRow}>
                 <span>Phí giao hàng (Viettel Post)</span>
                 <span>{new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(shippingFee)}</span>
               </div>
               <div className={styles.totalRow}>
                 <span>Tổng thanh toán</span>
                 <span className={styles.finalPrice}>{new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(totalPayment)}</span>
               </div>
            </div>

            <button type="submit" className="btn btn-primary" style={{width: '100%', padding: '1rem', fontSize: '1.125rem', marginTop: '1.5rem'}} disabled={loading}>
              {loading ? 'Đang xử lý...' : 'Xác nhận đặt hàng'}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

export default Checkout;

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ShoppingCart, Star, Heart, ArrowLeft } from 'lucide-react';
import { getProductByIdAPI, getCategoriesAPI, addReviewAPI } from '../data/api';
import { useCart } from '../contexts/CartContext';
import { useAuth } from '../contexts/AuthContext';
import styles from './ProductDetails.module.css';

const ProductDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { addToCart } = useCart();
  const { user } = useAuth();
  
  const [product, setProduct] = useState(null);
  const [categoryName, setCategoryName] = useState('');
  const [loading, setLoading] = useState(true);
  const [quantity, setQuantity] = useState(1);
  const [reviewText, setReviewText] = useState('');
  const [ratingInput, setRatingInput] = useState(5);

  useEffect(() => {
    const fetchProduct = async () => {
      setLoading(true);
      const data = await getProductByIdAPI(id);
      if (data) {
        setProduct(data);
        const cats = await getCategoriesAPI();
        const cat = cats.find(c => c.id === data.categoryId);
        if (cat) setCategoryName(cat.name);
      }
      setLoading(false);
    };
    fetchProduct();
  }, [id]);

  const handleAddToCart = () => {
    if (product) {
      addToCart(product, quantity);
      navigate('/cart');
    }
  };

  const handleAddReview = async (e) => {
    e.preventDefault();
    if (!user) {
      alert("Vui lòng đăng nhập để đánh giá");
      return;
    }
    if (!reviewText.trim()) return;
    
    try {
      const updatedProduct = await addReviewAPI(product.id, {
        userId: user.id,
        userName: user.name,
        rating: ratingInput,
        comment: reviewText
      });
      setProduct(updatedProduct);
      setReviewText('');
    } catch (err) {
      alert("Có lỗi xảy ra khi gửi đánh giá");
    }
  };

  if (loading) return <div className="container" style={{padding: '5rem 0', textAlign: 'center'}}>Đang tải sản phẩm...</div>;
  if (!product) return <div className="container" style={{padding: '5rem 0', textAlign: 'center'}}>Không tìm thấy sản phẩm.</div>;

  return (
    <div className={`container ${styles.detailsPage}`}>
      <button className={styles.backBtn} onClick={() => navigate(-1)}>
        <ArrowLeft size={20} /> Quay lại
      </button>

      <div className={styles.productLayout}>
        <div className={styles.imageSection}>
          <img src={product.image} alt={product.name} className={styles.mainImage} />
        </div>

        <div className={styles.infoSection}>
          <div className={styles.breadcrumbs}>
            <span>Trang chủ</span> / <span>{categoryName}</span> / <span className={styles.currentCrumb}>{product.name}</span>
          </div>

          <h1 className={styles.title}>{product.name}</h1>
          
          <div className={styles.meta}>
            <div className={styles.rating}>
              <Star fill="currentColor" size={18} className={styles.starIcon} />
              <span>{product.rating.toFixed(1)}</span>
              <span className={styles.reviewCount}>({product.reviews?.length || 0} đánh giá)</span>
            </div>
            <span className={styles.separator}>|</span>
            <div className={styles.stock}>Tình trạng: <span className={product.stock > 0 ? styles.inStock : styles.outOfStock}>{product.stock > 0 ? `Còn ${product.stock} sản phẩm` : 'Hết hàng'}</span></div>
          </div>

          <div className={styles.priceContainer}>
            <span className={styles.price}>{new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(product.price)}</span>
            {product.originalPrice > product.price && (
              <span className={styles.originalPrice}>
                {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(product.originalPrice)}
              </span>
            )}
            {product.originalPrice > product.price && (
               <span className="badge badge-pending" style={{marginLeft: '1rem'}}>-{Math.round(100 - (product.price/product.originalPrice)*100)}%</span>
            )}
          </div>

          <div className={styles.description}>
            <p>{product.description}</p>
          </div>

          <div className={styles.actions}>
            <div className={styles.quantityPicker}>
              <button onClick={() => setQuantity(q => Math.max(1, q - 1))} className={styles.qBtn}>-</button>
              <input type="number" min="1" max={product.stock} value={quantity} onChange={e => setQuantity(parseInt(e.target.value) || 1)} className={styles.qInput} />
              <button onClick={() => setQuantity(q => Math.min(product.stock, q + 1))} className={styles.qBtn}>+</button>
            </div>

            <button 
              className={`btn btn-primary ${styles.addToCartBig}`} 
              onClick={handleAddToCart}
              disabled={product.stock === 0}
            >
              <ShoppingCart size={20} />
              Thêm vào giỏ hàng
            </button>

            <button className={`btn btn-outline ${styles.wishlistBtn}`}>
              <Heart size={20} />
            </button>
          </div>
        </div>
      </div>

      {/* Reviews Section */}
      <div className={styles.reviewsSection}>
        <h2 className={styles.sectionTitle}>Đánh giá sản phẩm</h2>
        
        <div className={styles.reviewsList}>
          {product.reviews && product.reviews.length > 0 ? (
            product.reviews.map(review => (
              <div key={review.id} className={styles.reviewCard}>
                <div className={styles.reviewHeader}>
                  <div className={styles.reviewerAvatar}>{review.userName.charAt(0)}</div>
                  <div className={styles.reviewerInfo}>
                    <h4>{review.userName}</h4>
                    <div className={styles.reviewRating}>
                      {[...Array(5)].map((_, i) => (
                        <Star key={i} size={14} fill={i < review.rating ? "currentColor" : "none"} color={i < review.rating ? "var(--warning-color)" : "var(--text-muted)"} />
                      ))}
                    </div>
                  </div>
                </div>
                <p className={styles.reviewComment}>{review.comment}</p>
              </div>
            ))
          ) : (
             <p className={styles.noReviews}>Chưa có đánh giá nào. Hãy là người đầu tiên!</p>
          )}
        </div>

        {/* Add Review Form */}
        <div className={styles.addReviewForm}>
           <h3>Thêm đánh giá của bạn</h3>
           {user ? (
             <form onSubmit={handleAddReview}>
               <div className={styles.ratingSelect}>
                 <span>Đánh giá: </span>
                 <select value={ratingInput} onChange={e => setRatingInput(Number(e.target.value))} className="input-field" style={{width: 'auto', padding: '0.5rem'}}>
                   <option value={5}>5 Sao (Tuyệt vời)</option>
                   <option value={4}>4 Sao (Tốt)</option>
                   <option value={3}>3 Sao (Bình thường)</option>
                   <option value={2}>2 Sao (Kém)</option>
                   <option value={1}>1 Sao (Tệ)</option>
                 </select>
               </div>
               <textarea 
                 className="input-field" 
                 rows="4" 
                 placeholder="Nhận xét của bạn về sản phẩm..."
                 value={reviewText}
                 onChange={e => setReviewText(e.target.value)}
                 style={{marginBottom: '1rem', resize: 'vertical'}}
               ></textarea>
               <button type="submit" className="btn btn-primary">Gửi đánh giá</button>
             </form>
           ) : (
             <p>Vui lòng <a href="/login" style={{color: 'var(--primary-color)', fontWeight: '600'}}>đăng nhập</a> để gửi đánh giá.</p>
           )}
        </div>
      </div>
    </div>
  );
};

export default ProductDetails;
